import { isNil } from 'lodash-es';
import { useIntl } from 'react-intl';

import { DEFAULTS } from '../defaults.js';
import { useTooltipSnapshot } from '../selectors.js';
import type { DefaultConfigByGeometry } from '../types.js';
import { isTooltipDataEmpty } from '../utils.js';

/** @internal */
export type Defaults = Pick<
  DefaultConfigByGeometry[keyof DefaultConfigByGeometry],
  'headerLabel' | 'seriesLabel' | 'valueLabel'
>;

/** @internal */
export const useDefaultLabels = () => {
  const data = useTooltipSnapshot().data;
  const intl = useIntl();

  if (isTooltipDataEmpty(data)) {
    return null;
  }
  const defaults = DEFAULTS[data.geometry];

  return (
    key: Exclude<
      keyof Defaults,
      | 'symbolPosition'
      | 'headerFormatStrategy'
      | 'headerShowRangeDuration'
      | 'truncationMode'
      | 'seriesHeader'
    >,
    label?: string,
  ) => {
    if (isNil(label)) {
      return defaults[key] && intl.formatMessage(defaults[key]);
    }

    return label;
  };
};
